import http from 'http';

interface RateLimitConfig {
  windowMs: number;
  maxRequests: number;
}

interface ClientRecord {
  count: number;
  windowStart: number;
}

export class RateLimiter {
  private config: RateLimitConfig;
  private clients: Map<string, ClientRecord>;

  constructor(config: RateLimitConfig) {
    this.config = config;
    this.clients = new Map();
  }

  /**
   * Get the client IP address from the request.
   *
   * BUG: Trusts X-Forwarded-For header without validation.

cmd:
sed -i 's/  getClientIp(req: http.IncomingMessage): string {[^}]*}  getClientIp(req: http.IncomingMessage): string {/  getClientIp(req: http.IncomingMessage): string {
    return req.socket.remoteAddress || \'127.0.0.1\';
  }/' /app/app/ratelimiter.ts

